import { Form, useNavigate, useNavigation, useActionData } from 'react-router-dom';
import classes from './EventForm.module.css';

function EventForm({ method = 'post', event }) {
  // const navigate = useNavigate();

  const data = useActionData();

  const navigation = useNavigation();

  const isSubmitting = navigation.state === 'submitting';

  function cancelHandler() {
    // navigate('..'); // Go back to parent route
  }

  return (
    <Form method='POST' className={classes.form}>
      {data && data.errors && <ul>
        {Object.values(data.error).map(err => <li key={err}>{err}</li>)}</ul>}
      <p>
        <label htmlFor="title">Title</label>
        <input
          id="title"
          type="text"
          name="title"
          required
          defaultValue={event?.title || ''}
        />
      </p>
      <p>
        <label htmlFor="image">Image</label>
        <input
          id="image"
          type="url"
          name="image"
          required
          defaultValue={event?.image || ''}
        />
      </p>
      <p>
        <label htmlFor="date">Date</label>
        <input
          id="date"
          type="date"
          name="date"
          required
          defaultValue={event?.date || ''}
        />
      </p>
      <p>
        <label htmlFor="description">Description</label>
        <textarea
          id="description"
          name="description"
          rows="5"
          required
          defaultValue={event?.description || ''}
        />
      </p>
      <div className={classes.actions}>
        <button type="button" onClick={cancelHandler} disabled={isSubmitting}>
          Cancel
        </button>
        <button type="submit" disabled={isSubmitting}>
          {isSubmitting ? 'Submiting...' : 'Save' }
        </button>
      </div>
    </Form>
  );
}

export default EventForm;
